import React, { useState } from 'react';
import { askGeminiAboutMovies } from '../services/geminiService';

const AIConsultant: React.FC = () => {
  const [query, setQuery] = useState('');
  const [response, setResponse] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!query.trim()) return;

    setIsLoading(true);
    const result = await askGeminiAboutMovies(query);
    setResponse(result);
    setIsLoading(false);
  };

  return (
    <section className="py-16 bg-[#1d3a28] relative overflow-hidden">
      <div className="absolute top-0 left-0 w-full h-full opacity-10 pointer-events-none">
        <div className="absolute top-[-50px] left-[-50px] w-96 h-96 bg-[#9ccc65] rounded-full blur-[100px]" />
        <div className="absolute bottom-[-50px] right-[-50px] w-96 h-96 bg-[#7cb342] rounded-full blur-[100px]" />
      </div>

      <div className="container mx-auto px-6 relative z-10">
        <div className="max-w-3xl mx-auto text-center">
          <span className="text-[#9ccc65] font-bold text-sm uppercase tracking-widest mb-4 block">Film-Orakel</span>
          <h2 className="text-white text-4xl font-display mb-6">Was möchten Sie heute sehen?</h2>
          <p className="text-white/70 mb-8">Unser KI-Concierge hilft Ihnen dabei, das perfekte Kinoerlebnis basierend auf Ihrer Stimmung zu finden.</p>

          <form onSubmit={handleSubmit} className="flex flex-col sm:flex-row gap-4 mb-8">
            <input 
              type="text"
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              placeholder="z.B. 'Ich möchte etwas Spannendes aus Europa sehen'..."
              className="flex-1 px-6 py-4 rounded-full bg-white/10 border border-white/20 text-white placeholder-white/40 focus:outline-none focus:border-[#9ccc65]"
            />
            <button 
              disabled={isLoading}
              className="bg-[#7cb342] hover:bg-[#9ccc65] text-white px-8 py-4 rounded-full font-bold transition-all disabled:opacity-50"
            >
              {isLoading ? 'Denke nach...' : 'Fragen'}
            </button>
          </form>

          {response && (
            <div className="bg-white/5 border border-white/10 p-8 rounded-2xl text-left animate-fadeIn">
              <p className="text-white leading-relaxed italic">{response}</p>
            </div>
          )}
        </div>
      </div>
    </section>
  );
};

