                      FSK {movie.fsk}
                    </div>
                  </div>

                  {/* Movie Info & Times */}
                  <div className="flex-1 flex flex-col py-2">
                    <div className="mb-6">
                      <span className="text-[#7cb342] text-xs font-bold uppercase tracking-widest mb-2 block">{movie.genre}</span>
                      <h2 className="text-3xl font-display font-bold text-[#1d3a28] mb-2 group-hover:text-[#7cb342] transition-colors">{movie.title}</h2>
                      <p className="text-gray-400 text-sm italic mb-4">{movie.meta}</p>
                      <p className="text-gray-600 text-sm line-clamp-2 max-w-2xl">{movie.description}</p>
                    </div>

                    <div className="mt-auto">
                      <h4 className="text-xs font-bold uppercase text-gray-400 tracking-widest mb-4">Verfügbare Vorstellungen:</h4>
                      <div className="flex flex-wrap gap-3">
                        {todaysShowtimes.map((s, idx) => (
                          <button
                            key={idx}
                            onClick={() => handleBooking(movie.id, s.time)}
                            className={`px-8 py-3 rounded-2xl font-display font-bold text-xl transition-all border-2 ${
                              s.highlighted
                                ? 'bg-[#7cb342] border-[#7cb342] text-white hover:bg-[#9ccc65] hover:border-[#9ccc65]'
                                : 'bg-gray-50 border-gray-100 text-[#1d3a28] hover:border-[#1d3a28]'
                            }`}
                          >
                            {s.time}
                          </button>
                        ))}
                      </div>
                    </div>
                  </div>

                  {/* Action */}
                  <div className="hidden lg:flex flex-col justify-center items-center border-l border-gray-100 pl-8 pr-4">
                     <span className="text-gray-300 text-sm mb-4">{movie.duration} Min.</span>
                     <button className="text-[#1d3a28] font-bold hover:text-[#7cb342]">Details →</button>
                  </div>
                </div>
              );
            })}
          </div>
        ) : (
          <div className="bg-white rounded-[40px] p-20 text-center border border-dashed border-gray-200">
            <span className="text-6xl mb-6 block">🎬</span>
            <h3 className="text-2xl font-display text-[#1d3a28] mb-2">Keine Vorstellungen</h3>
            <p className="text-gray-500">Für diesen Tag sind derzeit keine Filme im Spielplan. Bitte wählen Sie ein anderes Datum.</p>
            <button 
              onClick={() => setSelectedDate(WEEK_DATES[0].fullDate)} 
              className="mt-8 text-[#7cb342] font-bold border-b border-[#7cb342]"
            >
              Zurück zum heutigen Tag
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

