                Zum anderen Standort
              </button>
            </div>
          </div>
        )}
      </div>

      {/* Modals */}
      {detailMovie && (
        <MovieDetailModal movie={detailMovie} onClose={() => setDetailMovie(null)} />
      )}
      {bookingData && (
        <BookingModal 
          movie={bookingData.movie} 
          time={bookingData.time} 
          date={activeDateObj?.dateStr || ''}
          onClose={() => setBookingData(null)} 
        />
